import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Avatar, Button, Textarea, icon } from 'decantr/components';

code.example:
function CommentThreadSidebar({ thread, currentUser, onReply, onResolve, onReact }) {
  const { div, span, time, p, button } = tags;
  const [replyText, setReplyText] = createSignal('');
  const [showReply, setShowReply] = createSignal(false);

  const handleSubmit = () => {
    if (replyText().trim()) {
      onReply(replyText());
      setReplyText('');
      setShowReply(false);
    }
  };

  return div({ class: css('_flex _col _gap3 _p4 paper-card _r2') },
    // Thread header
    div({ class: css('_flex _aic _jcsb _pb2 _borderB') },
      span({ class: css('_textsm _fgmuted') }, `${thread.comments.length} comments`),
      thread.resolved ? span({ class: css('_flex _aic _gap1 _textsm _fg[var(--success)]') },
        icon('check-circle', { size: '14' }), 'Resolved'
      ) : Button({ variant: 'ghost', size: 'xs', onclick: () => onResolve(thread.id) },
        icon('check', { size: '14' }), 'Resolve'
      )
    ),
    // Comments list
    ...thread.comments.map((comment, i) =>
      div({ class: css('_flex _gap3') },
        Avatar({ src: comment.author.avatar, fallback: comment.author.initials, size: 'sm' }),
        div({ class: css('_flex _col _gap1 _flex1') },
          div({ class: css('_flex _aic _gap2') },
            span({ class: css('_textsm _fontmedium') }, comment.author.name),
            time({ class: css('_textxs _fgmuted') }, comment.relativeTime)
          ),
          p({ class: css('_textsm') }, comment.content),
          // Reactions
          div({ class: css('_flex _aic _gap2 _mt1') },
            ...Object.entries(comment.reactions || {}).map(([emoji, users]) =>
              button({
                class: css('_flex _aic _gap1 _px2 _py0.5 _r1 _textsm _bg[var(--surface-raised)] _hover:bg[var(--surface)]'),
                onclick: () => onReact(comment.id, emoji)
              }, emoji, span({ class: css('_textxs _fgmuted') }, users.length))
            ),
            Button({ variant: 'ghost', size: 'xs', onclick: () => onReact(comment.id, null) },
              icon('smile', { size: '12' })
            )
          )
        )
      )
    ),
    // Reply input
    showReply() ? div({ class: css('_flex _col _gap2 _pt2 _borderT') },
      Textarea({
        placeholder: 'Write a reply...',
        value: replyText(),
        onInput: (e) => setReplyText(e.target.value),
        class: css('_textsm'),
        rows: 2
      }),
      div({ class: css('_flex _aic _gap2 _jce') },
        Button({ variant: 'ghost', size: 'sm', onclick: () => setShowReply(false) }, 'Cancel'),
        Button({ size: 'sm', onclick: handleSubmit }, 'Reply')
      )
    ) : Button({ variant: 'ghost', size: 'sm', onclick: () => setShowReply(true), class: css('_self[start]') },
      icon('reply', { size: '14' }), 'Reply'
    )
  );
}

