function InlineComment({ thread, position, onReply, onClose }) {
  const { div, span, p, input } = tags;
  const [replyText, setReplyText] = createSignal('');

  return div({
    class: css('_absolute _w[320px] _bg[var(--surface)] _shadow _r2 _border _z[50]'),
    style: `top: ${position.y}px; left: ${position.x}px`
  },
    // Header
    div({ class: css('_flex _aic _jcsb _p3 _borderB') },
      span({ class: css('_textsm _fontmedium') }, 'Comments'),
      Button({ variant: 'ghost', size: 'xs', onclick: onClose }, icon('x', { size: '14' }))
    ),
    // Comments
    div({ class: css('_p3 _flex _col _gap2 _max-h[200px] _overflow[auto]') },
      ...thread.comments.map(c =>
        div({ class: css('_flex _gap2') },
          Avatar({ src: c.author.avatar, size: 'xs' }),
          div({ class: css('_flex _col') },
            span({ class: css('_textxs _fontmedium') }, c.author.name),
            p({ class: css('_textxs') }, c.content)
          )
        )
      )
    ),
    // Quick reply
    div({ class: css('_p3 _borderT _flex _gap2') },
      input({
        type: 'text',
        placeholder: 'Reply...',
        class: css('_flex1 _px2 _py1 _textsm _border _r1'),
        value: replyText(),
        onInput: (e) => setReplyText(e.target.value),
        onKeyDown: (e) => e.key === 'Enter' && replyText() && onReply(replyText())
      }),
      Button({ size: 'sm', onclick: () => replyText() && onReply(replyText()) }, icon('send', { size: '12' }))
    )
  );
}

