function ResolvedThread({ thread, onReopen }) {
  const { div, span } = tags;

  return div({ class: css('_flex _aic _gap2 _p2 _bg[var(--surface-raised)] _r1 _opacity70') },
    icon('check-circle', { size: '14', class: css('_fg[var(--success)]') }),
    Avatar({ src: thread.resolvedBy.avatar, size: 'xs' }),
    span({ class: css('_textxs _fgmuted _flex1 _truncate') },
      `Resolved by ${thread.resolvedBy.name}`
    ),
    Button({ variant: 'ghost', size: 'xs', onclick: onReopen },
      icon('rotate-ccw', { size: '12' }), 'Reopen'
    )
  );
}

